<script setup>
import { ref, onMounted, onBeforeUnmount, nextTick } from 'vue'
import { useRouter } from 'vue-router'
import { supabase } from '@/lib/supabase.js'

const router = useRouter()

const isScrolled = ref(false)
const mobileOpen = ref(false)
const searchOpen = ref(false)
const searchQ    = ref('')
const searchInput = ref(null)

function onScroll() { isScrolled.value = window.scrollY > 60 }
onMounted(() => window.addEventListener('scroll', onScroll))
onBeforeUnmount(() => window.removeEventListener('scroll', onScroll))

function toggleSearch() {
  searchOpen.value = !searchOpen.value
  if (searchOpen.value) nextTick(() => searchInput.value?.focus())
}

function scrollToTop() { window.scrollTo({ top: 0, behavior: 'smooth' }) }
function scrollTo(id) {
  mobileOpen.value = false
  document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' })
}
function goLogin() { router.push('/login') }
function handleNavClick(link) {
  if (link.route) router.push(link.route)
  else scrollTo(link.id)
  mobileOpen.value = false
}

const navLinks = [
  { label: 'About',      id: 'about'    },
  { label: 'Admissions', id: 'apply'    },
  { label: 'Programs',   id: 'programs' },
  { label: 'News',       id: 'news'     },
  { label: 'Contact',    id: 'visit'    },
  { label: 'Portal',     route: '/login' },
]

const BG_URI = 'data:image/jpeg;base64,'
const slides = [
  { bg: BG_URI, title: 'Explore. Learn. Lead.',         sub: 'A future-ready university committed to excellence, innovation, and service to Cabuyao City and beyond.' },
  { bg: BG_URI, title: 'Quality Education for All.',    sub: 'Accessible, relevant, and world-class programs designed to empower every Filipino learner.' },
  { bg: BG_URI, title: 'Peace. Prosperity. Service.',   sub: 'Grounded in our core values, PNC shapes graduates who make a difference in their communities.' },
]
const currentSlide = ref(0)
let slideTimer = null
function goSlide(i) { currentSlide.value = i; resetTimer() }
function nextSlide() { currentSlide.value = (currentSlide.value + 1) % slides.length }
function resetTimer() { clearInterval(slideTimer); slideTimer = setInterval(nextSlide, 5000) }
onMounted(() => { slideTimer = setInterval(nextSlide, 5000) })
onBeforeUnmount(() => clearInterval(slideTimer))

// ── Leaflet Map ──
let leafletMap = null
onMounted(() => {
  // Dynamically load Leaflet CSS
  const link = document.createElement('link')
  link.rel  = 'stylesheet'
  link.href = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.css'
  document.head.appendChild(link)

  // Dynamically load Leaflet JS then init map
  const script = document.createElement('script')
  script.src = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js'
  script.onload = () => {
    const L = window.L
    leafletMap = L.map('pnc-map', { zoomControl: true, scrollWheelZoom: false })
      .setView([14.2584, 121.1333], 16)

    // OpenStreetMap tiles
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
      attribution: '© <a href="https://openstreetmap.org">OpenStreetMap</a> contributors',
      maxZoom: 19
    }).addTo(leafletMap)

    // Custom green marker
    const icon = L.divIcon({
      className: '',
      html: `<div style="
        background:#1a6b2e; color:#fff; border-radius:50% 50% 50% 0;
        width:36px; height:36px; display:flex; align-items:center; justify-content:center;
        font-size:18px; transform:rotate(-45deg); box-shadow:0 4px 12px rgba(0,0,0,.3);
        border:3px solid #fff;">
        <span style="transform:rotate(45deg)">📍</span>
      </div>`,
      iconSize: [36, 36],
      iconAnchor: [18, 36],
      popupAnchor: [0, -38]
    })

    L.marker([14.2584, 121.1333], { icon })
      .addTo(leafletMap)
      .bindPopup(`
        <div style="font-family:Inter,sans-serif; min-width:180px;">
          <div style="font-weight:700; color:#0f3d1c; font-size:14px; margin-bottom:4px;">
            Pamantasan ng Cabuyao
          </div>
          <div style="font-size:12px; color:#607060; line-height:1.6;">
            Gov. D.S. Mangubat Ave.<br>
            Cabuyao City, Laguna 4025
          </div>
          <a href="https://maps.google.com/?q=Pamantasan+ng+Cabuyao+Katapatan+Village+Banay-Banay+Cabuyao+Laguna" target="_blank"
            style="display:inline-block; margin-top:8px; font-size:12px;
            color:#1a6b2e; font-weight:600; text-decoration:none;">
            Open in Google Maps ↗
          </a>
        </div>
      `, { maxWidth: 240 })
      .openPopup()
  }
  document.head.appendChild(script)
})
onBeforeUnmount(() => { if (leafletMap) leafletMap.remove() })

const stats = [
  { num: '20+',  label: 'Programs Offered'   },
  { num: '5K+',  label: 'Students Enrolled'  },
  { num: '200+', label: 'Faculty & Staff'     },
  { num: '22',   label: 'Years of Excellence' },
]

const values = [
  { icon: 'bi-shield-check', label: 'Academic Excellence' },
  { icon: 'bi-people-fill',  label: 'Community Service'   },
  { icon: 'bi-globe2',       label: 'Global Competence'   },
]

const programs = [
  { name: 'College of Computing',     icon: 'bi-cpu-fill',         desc: 'Cutting-edge technology programs preparing students for the digital economy.',     courses: ['BSCS','BSIT','BSIS']   },
  { name: 'College of Engineering',   icon: 'bi-gear-fill',        desc: 'Building the engineers and innovators of tomorrow.',                               courses: ['BSCpE','BSEE','BSME']  },
  { name: 'College of Business',      icon: 'bi-briefcase-fill',   desc: 'Developing business leaders with local and global perspectives.',                  courses: ['BSBA','BSA','BSMA']    },
  { name: 'College of Education',     icon: 'bi-book-fill',        desc: 'Shaping compassionate, competent, and committed educators.',                       courses: ['BEEd','BSEd','BPEd']   },
  { name: 'Arts & Sciences',          icon: 'bi-palette-fill',     desc: 'Fostering critical thinkers and creative problem-solvers.',                        courses: ['BSPsych','ABComm','ABPS']},
  { name: 'College of Nursing',       icon: 'bi-heart-pulse-fill', desc: 'Training health professionals dedicated to compassionate care.',                   courses: ['BSN','BPT','BOT']      },
]

const applySteps = [
  'Fill out the online application form',
  'Submit required documents',
  'Take the PNC Admission Test',
  'Await results and enroll',
]

const allPrograms = ['BS Computer Science','BS Information Technology','BS Computer Engineering','BS Electronics Engineering','BS Business Administration','BS Accountancy','BS Education','BS Psychology','BS Nursing','AB Communication']

const appForm    = ref({ name: '', email: '', phone: '', program: '' })
const appSent    = ref(false)
const appLoading = ref(false)
const appError   = ref('')
const trackingCode = ref('')

async function submitApp() {
  if (!appForm.value.name || !appForm.value.email || !appForm.value.program) {
    appError.value = 'Please fill in Name, Email and Program.'
    return
  }
  appLoading.value = true
  appError.value   = ''
  try {
    const code = 'PNC-' + Math.random().toString(36).substring(2,8).toUpperCase()
    const { error } = await supabase.from('applications').insert({
      name:          appForm.value.name.trim(),
      email:         appForm.value.email.trim().toLowerCase(),
      phone:         appForm.value.phone.trim(),
      program:       appForm.value.program,
      status:        'pending',
      tracking_code: code
    })
    if (error) throw error
    trackingCode.value = code
    appSent.value      = true
    appForm.value      = { name: '', email: '', phone: '', program: '' }
  } catch (e) {
    appError.value = e.message || 'Submission failed. Please try again.'
    console.error('Admissions insert error:', e)
  } finally {
    appLoading.value = false
  }
}

const news = [
  { tag: 'Announcement', date: 'April 2, 2025',  title: 'Enrollment for AY 2025–2026 Now Open', body: 'PNC officially opens enrollment for the upcoming academic year. New students may apply online through our admissions portal.' },
  { tag: 'Events',       date: 'March 20, 2025', title: 'PNC Celebrates 22nd Founding Anniversary', body: 'The university community gathered to commemorate another year of academic excellence and community service.' },
  { tag: 'Achievement',  date: 'March 5, 2025',  title: 'PNC Students Excel in Regional Competition', body: 'Computing students bagged top awards at the regional ICT competition, showcasing their programming and innovation skills.' },
]
</script>

