.tb-login:hover { background: #d4a017; transform: translateY(-1px); }

/* NAVBAR */
.navbar { position: sticky; top: 0; z-index: 1000; background: #1a6b2e; display: flex; align-items: center; padding: 0 40px; height: 72px; gap: 24px; transition: background .3s, box-shadow .3s; }
.navbar.scrolled { background: rgba(15,61,28,.97); box-shadow: 0 4px 24px rgba(0,0,0,.25); }
.navbar::after { content: ''; position: absolute; bottom: 0; left: 0; right: 0; height: 3px; background: linear-gradient(90deg,#d4a017,#f0c832,#d4a017); }
.nav-brand { display: flex; align-items: center; gap: 12px; cursor: pointer; flex-shrink: 0; margin-right: 8px; }
.nav-logo { width: 52px; height: 52px; object-fit: contain; border-radius: 50%; border: 2px solid rgba(255,255,255,.3); background: rgba(255,255,255,.1); }
